var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠! 오늘은 언제 놀아줘?","JPN":"パパ！　今日はいつ遊んでくれるの？","ENG":"Daddy! When can you play with me today?","TWN":"爸爸！今天不陪我玩嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오늘은 안돼. 아빠는 돈을 버느라 바쁘단다.","JPN":"今日はダメだ。パパはお金を稼ぐのに忙しいんだよ。","ENG":"Not today. Daddy's busy making money.","TWN":"今天不行喔，爸爸要去賺錢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 내가 도와줄게! 조폐소를 우리 걸로 만들자!","JPN":"それなら私が助けてあげる！　造幣局を私たちのものに\\nしようよ！","ENG":"Oooh, then how about I help you? Let's take over the mint!","TWN":"那我幫你！我們去搶造幣廠吧！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그러면 굳이 돈을 벌 필요도 없잖아!","JPN":"そうすれば、お金を稼がなくて済むでしょ？","ENG":"Then, you don't have to work hard.","TWN":"那樣就不需要賺錢了！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그건 범죄란다. 아빤 결코 돈을 위해서 비리나 범죄를 저지르지 않아요.","JPN":"それは犯罪だよ。パパは決してお金のために犯罪を\\n犯したりはしないんだ。","ENG":"That's a crime. Your daddy is never going to commit crimes or corrupt acts to make money.","TWN":"那是犯罪，爸爸絕對不會為了掙錢而做非法勾當或犯罪。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아빠처럼 청렴한 인물은 스스로의 힘으로 돈을 버는 것에 자부심을 느끼거든.","JPN":"パパのように清廉潔白な人は、みずからの力でお金を稼ぐことに自負心を持っているんだ。","ENG":"Your daddy is an honest person, and honest people work hard to earn their money.","TWN":"像爸爸這樣清廉的人要憑藉自己的努力賺錢才有意義。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"범죄구나! 알겠어!","JPN":"犯罪なのね！　わかった！","ENG":"It's a crime, got it.","TWN":"原來是犯罪！知道了！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 나도 아빠처럼 정직하게 돈을 벌게!","JPN":"じゃあ私もパパみたいに真面目にお金を稼ぐよ！","ENG":"Then, I want to earn money honestly like you.","TWN":"那我也要像爸爸一樣誠實地賺錢！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"난 뭘 하면 될까? 응?","JPN":"私は何をすればいいのかな？　ねえねえ。","ENG":"How can I do that? Mm?","TWN":"那我該做什麼呢？嗯？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm...","TWN":"唔。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래, 언젠가 네가 이 회사를 물려받게 될지도 모르니 후계자 수업을 해보는 것도 좋겠구나.","JPN":"そうだな、いつか君がこの会社を引き継ぐかも\\nしれないから、後継者教育を受けておくと良いかもしれない。","ENG":"Well, one day I might decide to hand this company over to you. Maybe I should start training you for that.","TWN":"對了，你以後可能要繼承這家公司，現在不如上一些接班人課程吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"물려...... 받아?","JPN":"引き……継ぐ？","ENG":"Hand it over to me.","TWN":"接……班？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그냥 아빠가 계속 하면 안돼?","JPN":"パパがずっと続けるのはダメなの？","ENG":"Why can't you keep it?","TWN":"爸爸一直做下去不行嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사람 일이란 게 앞으로 어떻게 될지 모르는 일이잖니.","JPN":"人生は、いつどうなるかわからないからな。","ENG":"Because we don't know what might happen in the future.","TWN":"但是世事難料呀。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"날 두고 떠나진 않을 거지? 응?","JPN":"私のこと、置いて行ったりしないよね？　そうだよね？","ENG":"You're not going to leave me, are you?","TWN":"爸爸不會離開我吧？對不對？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"물론이지~ 아빠는 언제까지고 계속 여기 있을 거란다.","JPN":"もちろんだ～。パパはいつまでもここにいるよ。","ENG":"Of course not. Daddy is always going to be here for you.","TWN":"當然～爸爸會永遠在你身邊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 시그마. 너도 아빠가 하는 일을 배우면 아빠를 도와줄 수도 있겠지?","JPN":"だがシグマ。君がパパの仕事を覚えれば、パパのことを手伝ったりもできるだろう？","ENG":"But Sigma, if you learn what Daddy does, you can help him.","TWN":"不過西格瑪，你如果學到了爸爸的工作，以後就能幫爸爸更多的忙喔？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응, 아빠를 도와주는 거라면 뭐든지 할게!","JPN":"うん、パパの助けになるならなんでもやる！","ENG":"Okay, I can do anything to help you, Daddy.","TWN":"嗯，只要能幫到爸爸，我什麼都願意做！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"뭐부터 배우면 될까?","JPN":"何から覚えれば良いのかな？","ENG":"Where do you want me to start?","TWN":"那先從什麼開始呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음~ 부사장, 우리 회사 미래전략실 실장 자리가 지금 공석이었던가?","JPN":"よ～し。　副社長、我が社の未来戦略室長の\\nポジションは空席だったかな？","ENG":"Hm, Vice President, our Future Strategy Department's lead position is vacant, right?","TWN":"嗯~副總，我們公司的未來戰略室室長崗位是不是空缺啊？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 그런 부서도 없습니다만?","JPN":"部署名すら初耳ですが。","ENG":"We don't even have such a department.","TWN":"我們根本就沒有那種部門。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼 더욱 잘 됐군!","JPN":"それならなおさら良かった！","ENG":"That's better!","TWN":"那更好！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내일부턴 네가 미래전략실장이란다!","JPN":"明日からは君が未来戦略室の室長だ！","ENG":"As of tomorrow, you'll be the head of our Future Strategy Department.","TWN":"明天開始，你就是未來戰略室室長了！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내가 직접 많은 걸 가르쳐주마.","JPN":"私が色んなことを教えてあげるからな。","ENG":"I'll teach you as many things as I can.","TWN":"我會親自教你很多東西。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 좋아!","JPN":"うん！　わかった！","ENG":"Okie! Sounds perfect!","TWN":"嗯！好！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......아빠 놀이에도 꽤 익숙해지신 것 같군요.","JPN":"……パパ役にもだいぶ慣れてきたようですね。","ENG":"You've gotten used to playing father.","TWN":"……您好像對當爸爸遊戲越來越嫺熟了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"생각보다 즐겁군. 적성에 맞을지도 모르겠어.","JPN":"思ったより楽しいな。向いているのかもしれない。","ENG":"It's more entertaining than I thought. Maybe I'm father material.","TWN":"比我想像的要開心，也許很適合我也說不定。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......애 딸린 바람둥이 같으니.","JPN":"……まるで子持ちのカサノヴァみたい。","ENG":"... You're a womanizer with a child.","TWN":"……帶著孩子的花花公子。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"응? 자네 뭐라고 했나?","JPN":"うん？　いま、何と？","ENG":"Huh? Did you say something?","TWN":"嗯？你剛剛說什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무것도 아닙니다. 그건 그렇고......","JPN":"なんでもありません。それはそうと……","ENG":"Never mind. By the way,","TWN":"沒什麼，不過比起這個……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"학습이 빠른 만큼 금방 성숙해질 줄 알았더니, 갈수록 어리광만 느는 것 같네요.","JPN":"何事もすぐ覚えるので成長も早いかと思ったのですが、\\n日に日に甘えん坊になっていますね。","ENG":"she's not getting mature as quickly as she's learning. In fact, she's becoming more childish by the day.","TWN":"本以為她會隨著學習變得更成熟一些，沒想到反而變得越來越孩子氣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜인지는 몰라도 동화책 밖에 읽으려고 하질 않으니 어쩔 수 없지.","JPN":"なぜかはわからないが、絵本以外は読もうと\\nしないからな。仕方ないよ。","ENG":"For some reason, she wouldn't read anything but storybooks.","TWN":"不知道為什麼，她只願意讀童話書，真拿她沒辦法。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금으로선 다른 뭔가를 강요하고 싶지 않군.","JPN":"今は他の何かを押し付けたくはない。","ENG":"But for now, I don't want to force her to change.","TWN":"但我現在暫時不想強迫她做其他事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시그마가 과거를 잃어버리게 된 것에는, 내 책임이 가장 크니 말이야.","JPN":"シグマが過去の記憶をなくしてしまったのは、\\n私の責任が最も大きいからな。","ENG":"It's my fault that she lost her memories.","TWN":"因為西格瑪失去記憶的事情，我得負最大的責任。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 새 삶과 가족을 얻게 된 계기이기도 하죠.","JPN":"ですが、新しい人生と家族を手に入れるきっかけにも\\nなっていますよ。","ENG":"But she wouldn't have earned this new life or family if she hadn't.","TWN":"但那也是她獲得新生和家人的契機。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......그렇게 말해줘서 고맙네.","JPN":"……そう言ってくれるとありがたい。","ENG":"Thank you for saying that.","TWN":"……謝謝你這麼說。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌든 알겠습니다. 저도 시그마에 대해선 더 이상 참견하지 않도록 하죠.","JPN":"とにかく、話はわかりました。私もシグマに関しては\\nこれ以上口出ししないようにします。","ENG":"Anyway, I understand. I won't say anything about Sigma anymore.","TWN":"我明白了， 我以後也不會再干預西格瑪的事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그나마 요즘은 새 친구를 사귄 덕에 다른 직원들을 방해하진 않으니까요.","JPN":"最近は新しい友達ができたおかげで、従業員たちの\\n邪魔をすることもないですしね。","ENG":"At least for now, her new friend is keeping her occupied and safely away from our employees.","TWN":"畢竟她自從交到新的朋友之後，沒有再去打擾其他職員。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"오늘은 무척 기분이 좋아 보이는군! 시그마.","JPN":"今日はとってもご機嫌だな！　シグマ。","ENG":"You look happy today, Sigma.","TWN":"你今天看起來很開心！西格瑪。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 아빠가 내일부터 나도 회사에서 일하라고 했거든!","JPN":"うん！　明日からは私も会社で働くようにってパパに\\n言われたの！","ENG":"Yes! Daddy told me that I can work here, starting tomorrow.","TWN":"嗯！因為爸爸讓我從明天開始在公司工作了！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그치만 오늘은 아무 것도 하지 말고 기다리라니, 너무 심심해~","JPN":"でも、今日は何もしないで待てって言うの。退屈すぎるわ～！","ENG":"I just wish tomorrow would come quickly because I'm so bored right now.","TWN":"但今天我沒有事情做，好無聊~"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 무료할 땐 역시 사람들을 돕는 게 최고라네!","JPN":"うむ！　退屈なときはやっぱり人助けが最高だ！","ENG":"Mm! If you're bored, we can always go help others.","TWN":"嗯！幫助別人是打破無聊的最好的方法！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"사람들을 도울만한 좋은 생각이 있는가?","JPN":"人助けのための良いアイデアはあるだろうか？","ENG":"Got any idea about what we can do?","TWN":"有沒有什麼能幫助別人的事情呢？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으음~","JPN":"う～ん……","ENG":"Mm...","TWN":"嗯~"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......청소!","JPN":"……掃除！","ENG":"We can clean!","TWN":"……打掃！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"낙엽이 쌓인 거리를 깨끗하게 청소하러 가자!","JPN":"街中を綺麗に掃除しよう！","ENG":"We can clean leaves off the streets!","TWN":"我們去打掃大街上的落葉吧！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 사람들이 깨끗해진 거리를 보고 좋아할 거야!","JPN":"綺麗になったのを見て、みんな喜ぶと思う！","ENG":"Clean streets make people happy!","TWN":"人們看到變乾淨的街頭一定會很開心！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 그거 좋군! 바로 출발하지!","JPN":"ガハハ！　それはいい考えだ！　今すぐ出発するとしよう！","ENG":"Hah hah! That's a good idea. Let's go!","TWN":"哈哈！好主意！我們走吧！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};